INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_restorative-reproductive-medicine', 'restorative-reproductive-medicine', 'Restorative Reproductive Medicine (RRM)', 'I', 0, '<p><strong>A specialized medical approach focused on identifying and correcting underlying causes of infertility, recurrent miscarriage, gynecologic pain, abnormal bleeding, and other reproductive dysfunctions,</strong> aiming to restore natural fertility and physiological function rather than bypass or suppress it. RRM includes lifestyle changes, patient education in fertility cycle awareness, medical treatments supporting ovulation and implantation, and surgery to remove pathologic tissue and restore normal anatomy. The goal is improved health, which leads to the natural ability to conceive.<sup><a href="#ref-2">2</a></sup><sup><a href="#ref-3">3</a></sup><sup><a href="#ref-4">4</a></sup><sup><a href="#ref-1">1</a></sup></p>', 'RRM', '/what-is-rrm/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_root-cause-diagnosis', 'root-cause-diagnosis', 'Root Cause Diagnosis', 'I', 1, '<p><strong>The foundational RRM principle that reproductive health problems (including infertility, abnormal bleeding, and chronic pain) are symptoms of identifiable underlying causes, not final diagnoses in themselves.</strong> Underlying causes may include hormonal imbalances, structural abnormalities (e.g., tubal blockage, uterine defects), inflammatory conditions, autoimmune disorders, metabolic dysfunction, or iatrogenic factors such as C-section scar defects or prior surgical complications. RRM does not accept "unexplained infertility" as a final answer, but continues deeper investigation to find treatable hidden causes.<sup><a href="#ref-3">3</a></sup><sup><a href="#ref-4">4</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_restorative-as-a-principle', 'restorative-as-a-principle', 'Restorative (as a Principle)', 'I', 2, '<p><strong>Pertaining to the goal of repairing, healing, and optimizing the natural function of the reproductive system.</strong> The restorative approach contrasts with suppressive therapies (e.g., hormonal contraception used to mask cycle symptoms) and bypass therapies (e.g., IVF circumventing tubal disease). It also encompasses removal of problematic devices and reversal of prior procedures such as tubal ligation to restore health or fertility potential.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_natural-fertility', 'natural-fertility', 'Natural Fertility', 'I', 3, '<p><strong>The inherent biological capacity for reproduction through in vivo (in the body) conception, without gamete removal or external fertilization.</strong> RRM aims to restore or optimize natural fertility through corrective medical and surgical interventions, including procedures like tubal reversal.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_body-literacy', 'body-literacy', 'Body Literacy', 'I', 4, '<p><strong>An individual''s informed understanding of their own biological signs and reproductive cycle,</strong> typically developed through systematic fertility charting. Body literacy empowers patients to recognize abnormalities early, time intercourse and diagnostics appropriately, and participate actively in their own care.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_comprehensive-evaluation', 'comprehensive-evaluation', 'Comprehensive Evaluation', 'I', 5, '<p><strong>A thorough RRM assessment designed to identify underlying conditions.</strong> Typically includes detailed cycle charting (using the Creighton Model or other FABMs), timed hormonal blood tests, ultrasound series (including saline infusion sonohysterogram for structural assessment), hysterosalpingogram (HSG), semen analysis, and targeted testing for endocrine, immune, clotting, or genetic factors. Diagnostic and/or operative laparoscopy and hysteroscopy are employed when indicated, essential for definitive diagnosis of endometriosis, pelvic adhesions, chronic endometritis, and isthmoceles.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_personalized-treatment', 'personalized-treatment', 'Personalized Treatment', 'I', 6, '<p><strong>The practice of tailoring medical and/or surgical interventions to the specific underlying conditions identified during evaluation,</strong> incorporating patient goals (e.g., desire for future fertility influences the choice of isthmocele repair method). Treatment plans may include targeted hormonal therapy, ovulation induction, luteal phase support, nutritional protocols, lifestyle modifications, and specialized surgery.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_holistic-approach', 'holistic-approach', 'Holistic Approach', 'I', 7, '<p><strong>Consideration of the whole person and the interplay of bodily systems</strong> (endocrine, immune, metabolic, inflammatory, musculoskeletal) and their collective impact on reproductive health. RRM addresses genetics, lifestyle, prior interventions, and overall systemic wellness alongside specific pelvic pathology.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_reproductive-health-optimization', 'reproductive-health-optimization', 'Reproductive Health Optimization', 'I', 8, '<p><strong>The overarching RRM goal of improving the overall health and function of the reproductive system</strong>: encompassing fertility, cycle regularity, absence of pain or abnormal bleeding, hormonal balance, and long-term gynecologic wellness. Achieving pregnancy is a result of restored health, not merely the isolated procedural endpoint.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_corrective-vs-bypass', 'corrective-vs-bypass', 'Corrective vs. Bypass/Suppressive', 'I', 9, '<p><strong>A key RRM conceptual distinction.</strong> RRM aims to correct underlying anatomical, hormonal, or immunological problems (e.g., surgical repair of fallopian tubes, isthmocele reconstruction, adhesion excision), whereas bypass therapies circumvent infertility problems (IVF bypasses tubal blockage), suppressive therapies mask symptoms (hormonal contraception for endometriosis pain), and hysterectomy removes the affected organ entirely.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fabms', 'fabms', 'Fertility Awareness-Based Methods (FABMs)', 'II', 0, '<p><strong>An umbrella term for scientific methods used to monitor and interpret biological signs of fertility (biomarkers) throughout the menstrual cycle.</strong> FABMs can be used for health monitoring, timing diagnostics and treatments in RRM, and achieving or avoiding pregnancy. A 2025 systematic review of 20,339 participants from 16 studies found that FABMs, when used correctly, were associated with a success rate of over 90% for both contraception and conception purposes. FABMs encourage partner involvement, improve communication, and enhance body literacy by tracking female biomarkers to determine fertility status, and can also help diagnose ovulation-related disorders such as PCOS and endometriosis. Note: The Creighton Model FertilityCare System is specifically classified as an NFP method by its developers and is distinct from the FABM umbrella.<sup><a href="#ref-5">5</a></sup><sup><a href="#ref-6">6</a></sup></p>', 'FABMs', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fertility-charting', 'fertility-charting', 'Fertility Charting', 'II', 1, '<p><strong>The systematic daily recording of fertility biomarkers according to a specific standardized method,</strong> such as the Creighton Model or another FABM. Chart data function analogously to an ECG for the reproductive system, revealing hormonal patterns, potential abnormalities, and optimal windows for diagnostics, treatment timing, and intercourse. Changes in charting patterns serve as a form of biofeedback to assess treatment efficacy.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_biomarkers', 'biomarkers', 'Biomarkers (Fertility)', 'II', 2, '<p><strong>Observable biological signs that change predictably across the menstrual cycle and indicate reproductive status.</strong> Primary biomarkers directly reflect hormonal activity: cervical mucus characteristics (appearance, sensation, elasticity) shift with rising estrogen, basal body temperature (BBT) rises 0.2 to 0.5 degrees C after progesterone release, and hormone levels (LH, FSH, estradiol, progesterone) are measurable via blood tests or urine metabolites. Secondary biomarkers include cycle length patterns, bleeding characteristics, cervical position and texture, mittelschmerz (mid-cycle pelvic pain), and breast tenderness. In RRM, biomarkers function clinically rather than merely observationally: charted patterns identify the fertile window, confirm ovulation, flag luteal phase deficiency, and time cycle-phase-specific diagnostics and treatments.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_nfp', 'nfp', 'Natural Family Planning (NFP)', 'II', 3, '<p><strong>Methods used to achieve or avoid pregnancy based on identifying the fertile window through observation of biological signs.</strong> The Creighton Model FertilityCare System is a specific, standardized NFP method foundational to NaProTECHNOLOGY. NFP and FABM are sometimes used interchangeably in clinical literature, though they are not identical categories.</p>', 'NFP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_creighton-model', 'creighton-model', 'Creighton Model FertilityCare System (CrMS)', 'II', 4, '<p><strong>A standardized, prospective method of Natural Family Planning (NFP) focused on detailed observation and classification of cervical mucus patterns and other biological markers,</strong> developed at the Pope Paul VI Institute by Dr. Thomas Hilgers. The CrMS is distinct from the broader FABM category. Its developers specifically distinguish it as an NFP method. The CrMS provides precise information for monitoring gynecologic health and fertility and forms the diagnostic foundation for NaProTECHNOLOGY, allowing cycle-phase-specific timing of blood tests and medical treatments. Published effectiveness data show CrMS is up to 98% effective for achieving pregnancy in couples with normal fertility and, in conjunction with NaPro, up to 80% effective for couples experiencing infertility. A prospective cohort study (CEIBA) in 17 CrMS centers across the USA and Canada found the highest 13-cycle pregnancy rate with correct use to conceive was 89.6%, when intercourse was timed to peak-type mucus days.<sup><a href="#ref-7">7</a></sup><sup><a href="#ref-8">8</a></sup><sup><a href="#ref-9">9</a></sup></p>', 'CrMS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_peak-day', 'peak-day', 'Peak Day', 'II', 5, '<p><strong>In mucus-based methods (including the Billings Ovulation Method), the last day of fertile-type cervical mucus</strong> (characterized as clear, stretchy, or lubricative) correlating closely with the time of ovulation. In CrMS, Peak Day identification is critical for timing luteal progesterone support in NaPro Medical protocols.<sup><a href="#ref-8">8</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_billings-ovulation-method', 'billings-ovulation-method', 'Billings Ovulation Method', 'II', 6, '<p><strong>A standardized FABM developed by Australian physicians Drs. John and Evelyn Billings in the 1960s, based entirely on the sensation and appearance of cervical mucus at the vulva to identify the fertile window.</strong> The Billings method requires no temperature taking and no instruments, making it globally accessible across cultural and resource settings; it has been studied in field trials supported by the World Health Organization. Users record daily observations according to standardized rules, identifying the "Peak Day" (the last day of fertile-type mucus) and counting subsequent infertile days. Published effectiveness data from large multi-country trials report method-related pregnancy rates of approximately 1% per year when used correctly to avoid pregnancy. Billings is the foundational mucus-based method from which the Creighton Model was later standardized; it shares core mucus methodology with CrMS while remaining a distinct method with its own teaching network.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_femm', 'femm', 'FEMM (Fertility Education and Medical Management)', 'II', 7, '<p><strong>An FABM program integrating hormonal science with cycle charting and providing a structured framework for medical management based on cycle data.</strong> FEMM incorporates hormone monitoring alongside mucus observations and is used both for family planning and for gynecological health management within RRM.<sup><a href="#ref-1">1</a></sup></p>', NULL, '/femm/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sympto-thermal-method', 'sympto-thermal-method', 'Sympto-Thermal Method (STM)', 'II', 8, '<p><strong>A cycle charting method combining multiple biomarkers</strong> (primarily cervical mucus changes and basal body temperature (BBT) shifts) to identify the fertile window. BBT rises approximately 0.2 to 0.5 degrees C following ovulation due to progesterone secretion from the corpus luteum. STM identifies the pre-ovulatory and post-ovulatory infertile phases using both markers.</p>', 'STM', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_marquette-method', 'marquette-method', 'Marquette Method', 'II', 9, '<p><strong>A FABM developed at Marquette University by Dr. Richard Fehring and colleagues that uses the ClearBlue Fertility Monitor to measure urinary estrogen and LH metabolites, producing objective low, high, and peak fertility readings.</strong> The monitor-based protocol can be used alone or combined with cervical mucus and basal body temperature observations, depending on user preference. Quantifiable hormone data provides a second independent confirmation of fertility status, which is particularly valuable for women with irregular cycles, postpartum and breastfeeding women, and women in perimenopause, where mucus patterns alone may be harder to interpret. Published effectiveness data from prospective cohort studies report perfect-use pregnancy rates of approximately 2% per year to avoid pregnancy. Marquette is also used clinically through the FACTS (Fertility Appreciation Collaborative to Teach the Science) training program; see <a href="#marquette-protocol">Marquette Method Clinical Protocol</a> for the medical-management arm.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_bbt', 'bbt', 'Basal Body Temperature (BBT)', 'II', 10, '<p><strong>The body''s resting temperature, measured orally or vaginally first thing in the morning after at least three hours of uninterrupted sleep and before any activity, eating, or drinking.</strong> BBT rises 0.2 to 0.5 degrees C within one to three days after ovulation due to the thermogenic effect of progesterone released by the corpus luteum; this sustained shift produces a characteristic biphasic pattern on a cycle chart. A thermal shift confirms that ovulation has occurred but cannot predict ovulation in advance. BBT is therefore useful for retrospective ovulation confirmation, luteal phase length measurement, and detection of a short luteal phase (&lt;10 days) or anovulation, but is not reliable as the sole marker for identifying the fertile window. Accuracy depends on consistent timing, adequate sleep, and the absence of confounders (illness, alcohol, disturbed sleep, shift work). BBT is a core component of sympto-thermal methods and a secondary confirmatory marker in several other FABMs.</p>', 'BBT', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_naprotechnology-definition', 'naprotechnology-definition', 'NaProTECHNOLOGY (Natural Procreative Technology)', 'III', 0, '<p><strong>A specific women''s health science focused on reproductive and gynecologic health, developed by Dr. Thomas Hilgers at the Pope Paul VI Institute.</strong> It utilizes the Creighton Model FertilityCare System for precise cycle monitoring to guide targeted medical (NaPro Medical) and surgical (NaPro Surgery/Advanced Reproductive Surgery) treatments based on identified cycle abnormalities. NaProTECHNOLOGY works cooperatively with the reproductive system and does not employ methods that are inherently suppressive, circumventive, or destructive. In Hilgers (2004), a cohort of 1,045 infertile patients reported cumulative live-birth rates exceeding 60% by 24 months and approximately 70% by 36 months.<sup><a href="#ref-10">10</a></sup> More recently, Sanchez-Mendez et al. (2025) followed 1,310 couples and reported cumulative live-birth rates of 50% at 24 months and 62.1% at 36 months or longer.<sup><a href="#ref-11">11</a></sup><sup><a href="#ref-12">12</a></sup> Both figures are comparable to or higher than cumulative live-birth rates achieved after one or more IVF cycles</p>', NULL, '/naprotechnology/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_napro-medical', 'napro-medical', 'NaPro Medical', 'III', 1, '<p><strong>The medical management component of NaProTECHNOLOGY, using timed medications and supplements based on Creighton Model charting data.</strong> Treatments are cycle-phase-specific (e.g., luteal progesterone support is timed to the post-peak phase; ovulation induction agents are timed to the follicular phase). Common interventions include targeted hormone therapy (progesterone, estrogen, HCG), ovulation induction (clomiphene, letrozole), thyroid management, and treatment of conditions like hyperprolactinemia or insulin resistance.<sup><a href="#ref-11">11</a></sup><sup><a href="#ref-12">12</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_napro-surgery', 'napro-surgery', 'NaPro Surgery / Advanced Reproductive Surgery', 'III', 2, '<p><strong>The specialized surgical component of NaProTECHNOLOGY, employing meticulous, often minimally invasive techniques to restore anatomy and function or remove problematic conditions.</strong> Hallmarks include excision (rather than ablation/fulguration) of endometriosis, meticulous adhesiolysis with anti-adhesion barrier protocols, microsurgical tubal repair and reversal, multi-layer isthmocele reconstruction, and fertility-preserving ovarian surgery. Published results have documented adhesion scores dropping dramatically with the introduction of extensive Gore-Tex barrier use in NaPro surgeries, from a mean score of 33.3 to 6.0 over a decade.<sup><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fertilitas-study', 'fertilitas-study', 'Fertilitas Study', 'III', 3, '<p><strong>One of the largest single-center NaProTECHNOLOGY cohort studies to date,</strong> demonstrating a take-home baby (THB) rate of 35.3% overall, rising to 62.1% among patients who remained with the program for the full duration of treatment. The study confirmed NaPro as associated with a notably high THB rate even in patients with unfavorable prognostic factors such as advanced maternal age, prolonged infertility duration, and prior failed ART attempts. Conditions associated with higher THB rates included recurrent pregnancy loss, hormonal/functional disorders, endometriosis, and male factor infertility.<sup><a href="#ref-13">13</a></sup><sup><a href="#ref-14">14</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_femm-medical-management', 'femm-medical-management', 'FEMM Medical Management', 'III', 4, '<p><strong>The clinical treatment arm of the FEMM (Fertility Education and Medical Management) program,</strong> in which trained medical providers use cycle charting data (cervical mucus observations and urinary LH testing) alongside cycle-timed lab work to diagnose and treat reproductive and hormonal disorders. FEMM Medical Providers follow protocols developed by the Reproductive Health Research Institute (RHRI) under Dr. Pilar Vigil. Treatment categories include PCOS, thyroid dysfunction, luteal phase deficiency, recurrent pregnancy loss, anovulation, and menopausal disorders. FEMM is distinct from NaProTechnology in its charting method (sympto-hormonal rather than Creighton-only), institutional affiliation (RHRI rather than Saint Paul VI Institute), and protocol framework.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_femm-levels', 'femm-levels', 'FEMM Education Levels (Teen, Adult, Medical)', 'III', 5, '<p><strong>FEMM offers three tiered pathways matched to life stage and clinical need.</strong> Teen FEMM introduces adolescent girls to the hormonal and ovulatory basis of the menstrual cycle as a vital sign of overall health, without contraceptive framing. Adult FEMM teaches cycle charting (sympto-hormonal approach with mucus observation and optional urinary LH testing) for use in family planning and health awareness. FEMM Medical Management is the clinical arm in which trained FEMM Medical Providers use charting data alongside cycle-timed lab work to diagnose and treat hormonal and reproductive disorders (see <a href="#femm-medical-management">FEMM Medical Management</a>). The three tiers allow FEMM content to meet users at different stages of the reproductive life course with appropriate depth and clinical integration.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_rhri', 'rhri', 'Reproductive Health Research Institute (RHRI)', 'III', 6, '<p><strong>The research and training organization behind FEMM''s medical management protocols,</strong> founded by Dr. Pilar Vigil, a specialist in obstetrics, gynecology, and reproductive endocrinology. RHRI has published peer-reviewed research linking chronic anovulation to long-term health risks including cardiovascular disease and Type 2 diabetes, and has developed clinical protocols for PCOS phenotyping, thyroid-related cycle disruption, and immune evaluation for recurrent pregnancy loss.<sup><a href="#ref-1">1</a></sup></p>', 'RHRI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sympto-hormonal-method', 'sympto-hormonal-method', 'Sympto-Hormonal Method', 'III', 7, '<p><strong>A fertility awareness-based method that combines cervical mucus observation with urinary hormone testing (typically LH strips) to track ovulation.</strong> FEMM uses a sympto-hormonal approach, distinguishing it from mucus-only methods (Creighton, Billings) and sympto-thermal methods (which add basal body temperature). The addition of objective hormone data provides a second independent confirmation of ovulatory events.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_neofertility', 'neofertility', 'NeoFertility', 'III', 8, '<p><strong>A clinical system developed by Dr. Phil Boyle that builds on NaProTechnology training with expanded diagnostic protocols, particularly in reproductive immunology and androgen evaluation.</strong> NeoFertility treats infertility, recurrent miscarriage, and at-risk pregnancy using a structured three-phase process: comprehensive diagnosis (Phase 1), treatment and cycle optimization (Phase 2), and conception timing with confirmed follicle rupture (Phase 3). NeoFertility is method-agnostic: it accepts charting data from any FABM, not only the Creighton Model.<sup><a href="#ref-1">1</a></sup></p>', NULL, '/neofertility/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_chartneo', 'chartneo', 'ChartNeo', 'III', 9, '<p><strong>NeoFertility''s digital charting platform that integrates patient charting data with the clinical workflow.</strong> ChartNeo connects patients, fertility advisors, and clinicians through shared data, enabling remote monitoring and telehealth delivery. Unlike standalone charting apps, ChartNeo is designed as a clinical tool that feeds directly into diagnostic and treatment decisions.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ldn', 'ldn', 'Low-Dose Naltrexone (LDN)', 'III', 10, '<p><strong>An immune-modifying agent used at 4.5 mg nightly in the NeoFertility protocol for patients with reduced egg reserve, suspected immune-mediated implantation failure, and endorphin deficiency.</strong> Originally developed as an opioid antagonist at higher doses, LDN at low doses modulates immune function by temporarily blocking opioid receptors, triggering a compensatory increase in endorphin production. Published data from NeoFertility shows LDN use associated with significant enhancements in endometrial thickness, ovarian responsiveness, progesterone levels, and clinical pregnancy rates.</p>', 'LDN', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_dhea-supplementation', 'dhea-supplementation', 'DHEA (Dehydroepiandrosterone) in RRM', 'III', 11, '<p><strong>An androgen precursor used in NeoFertility protocols to address hypoandrogenemia, abnormally low androgen levels identified as a contributor to recurrent pregnancy loss and diminished ovarian reserve.</strong> DHEA evaluation is part of NeoFertility''s expanded diagnostic panel. When indicated, supplementation aims to restore androgen levels that support follicular development and early pregnancy maintenance.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_immune-modifying-framework', 'immune-modifying-framework', 'Immune-Modifying Framework', 'III', 12, '<p><strong>NeoFertility''s systematic approach to evaluating and treating immunological factors in infertility and recurrent miscarriage.</strong> The framework includes NK cell panels (natural killer cell activity), food antibody testing, chromosomal abnormality screening, blood clotting markers, and chronic endometritis investigation. Treatment may include LDN, intralipid infusions, corticosteroids, and anticoagulation therapy. This represents one of NeoFertility''s most significant expansions beyond standard NaProTechnology protocols.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_marquette-protocol', 'marquette-protocol', 'Marquette Method Clinical Protocol', 'III', 13, '<p><strong>A fertility awareness-based method that uses the ClearBlue Fertility Monitor to measure urinary estrogen and LH levels, providing objective hormone data alongside optional cervical mucus and temperature observations.</strong> Developed at Marquette University, the method has been integrated into clinical RRM practice through the FACTS training program. The monitor-based approach appeals to clinicians who want quantifiable hormone data as part of the diagnostic workup. Marquette-trained Medical Consultants use the charting data for cycle-timed diagnostics in a framework similar to NaProTechnology and FEMM.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hcg-trigger', 'hcg-trigger', 'HCG Trigger (Human Chorionic Gonadotropin Trigger)', 'III', 14, '<p><strong>A single injection of human chorionic gonadotropin (hCG) given during an ovulation induction or monitored cycle to mimic the natural LH surge, triggering final follicular maturation and ovulation.</strong> In NaPro Medical and related RRM protocols, hCG triggering is used selectively when cycle-timed monitoring identifies a mature follicle with a delayed or absent endogenous LH surge, or to improve the precision of ovulation timing in combination with ovulation induction agents such as clomiphene or letrozole. Post-ovulatory hCG "boosters" also support corpus luteum function and early luteal progesterone production. Unlike IVF protocols, which use hCG triggering to time oocyte retrieval, RRM protocols use it to support natural intercourse-timed conception within the body.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_follicle-maturation-study', 'follicle-maturation-study', 'Follicle Maturation Study (Follicle Tracking / Follicular Ultrasound Series)', 'IV', 0, '<p><strong>A series of transvaginal ultrasounds performed across the follicular phase of the menstrual cycle</strong> to monitor follicle growth, dominant follicle selection, and ovulation. Findings inform diagnosis of luteinized unruptured follicle (LUF) syndrome, ovulatory dysfunction, and are used to time hormonal interventions precisely.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sis', 'sis', 'Saline Infusion Sonohysterogram (SIS) / "Bubble Test"', 'IV', 1, '<p><strong>A transvaginal ultrasound performed while infusing sterile saline into the uterine cavity,</strong> providing enhanced visualization of the endometrial cavity and uterine walls. SIS is the primary diagnostic tool for uterine isthmocele, enabling measurement of the defect dimensions and residual myometrial thickness. It also detects endometrial polyps, submucosal fibroids, intrauterine adhesions, and uterine septa, and can assess tubal patency.<sup><a href="#ref-15">15</a></sup><sup><a href="#ref-16">16</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hsg', 'hsg', 'Hysterosalpingogram (HSG)', 'IV', 2, '<p><strong>A radiographic procedure in which contrast dye is introduced through the cervix into the uterine cavity and fallopian tubes under fluoroscopic guidance.</strong> HSG assesses uterine cavity morphology and tubal patency. It is often the first-line imaging tool for evaluating tubal factor infertility.<sup><a href="#ref-17">17</a></sup></p>', 'HSG', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_selective-salpingography', 'selective-salpingography', 'Selective Salpingography', 'IV', 3, '<p><strong>A specialized variant of HSG in which contrast dye is injected selectively into each fallopian tube individually via a catheter.</strong> This allows targeted assessment and, in some cases, simultaneous therapeutic recanalization of proximal tubal blockages.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hysteroscopy-diagnostic', 'hysteroscopy-diagnostic', 'Hysteroscopy (Diagnostic)', 'IV', 4, '<p><strong>Direct visualization of the uterine cavity and cervical canal using a hysteroscope (a thin, illuminated camera).</strong> Considered the gold standard for evaluation and management of intrauterine pathology. Diagnostic hysteroscopy is indicated for evaluation of abnormal uterine bleeding, recurrent miscarriage, repeated implantation failure, and suspected structural abnormalities. In premenopausal women with regular cycles, optimal timing is during the early follicular phase after menstruation.<sup><a href="#ref-18">18</a></sup><sup><a href="#ref-17">17</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hysteroscopy-operative', 'hysteroscopy-operative', 'Hysteroscopy (Operative)', 'IV', 5, '<p><strong>A therapeutic extension of diagnostic hysteroscopy, used to treat intrauterine pathology identified during visualization.</strong> ACOG-recognized indications include removal of endometrial polyps, submucosal leiomyomas (fibroids), uterine septa, intrauterine adhesions (synechiae), retained products, malpositioned IUDs, tubal cannulation, and treatment of isthmoceles. Ambulatory (office-based) hysteroscopy offers comparable outcomes to operating room procedures with reduced cost and avoidance of general anesthesia.<sup><a href="#ref-17">17</a></sup><sup><a href="#ref-18">18</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_laparoscopy-diagnostic', 'laparoscopy-diagnostic', 'Laparoscopy (Diagnostic)', 'IV', 6, '<p><strong>Minimally invasive visualization of the pelvic and abdominal organs through small incisions using a laparoscope.</strong> In RRM, diagnostic laparoscopy is often the definitive method for diagnosing endometriosis and pelvic adhesions, conditions frequently missed on imaging alone. The Systematic Mapping of the Abdomen and Pelvis (S-MAP) protocol is employed during NaPro diagnostic laparoscopy for comprehensive abdominal and pelvic assessment.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_laparoscopy-operative', 'laparoscopy-operative', 'Laparoscopy (Operative)', 'IV', 7, '<p><strong>Minimally invasive surgical treatment performed laparoscopically</strong> for conditions including endometriosis (via excision), pelvic adhesions (adhesiolysis), uterine fibroids (myomectomy), ovarian cysts (cystectomy), fallopian tube disease (repair, reversal, neosalpingostomy), isthmocele (laparoscopic excision and multi-layer reconstruction), and PCOS (ovarian wedge resection).<sup><a href="#ref-17">17</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_near-contact-laparoscopy', 'near-contact-laparoscopy', 'Near Contact Laparoscopy', 'IV', 8, '<p><strong>A specialized laparoscopic technique in which the laparoscope is brought into close proximity to tissue to achieve high-magnification visualization.</strong> Used in NaPro Surgery for precise identification of subtle endometriosis implants and peritoneal disease that might be missed at standard laparoscopic distance.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_s-map', 's-map', 'S-MAP (Systematic Mapping of the Abdomen and Pelvis)', 'IV', 9, '<p><strong>A methodical, standardized protocol for comprehensive examination of all abdominal and pelvic structures during laparoscopy,</strong> ensuring that no area of disease is overlooked. The S-MAP method follows the systematic evaluation sequence described by Dr. Thomas Hilgers in the NaProTECHNOLOGY textbook (Chapter 63); the term "S-MAP" was coined by Dr. Naomi Whittaker. Used in combination with Near-Contact Laparoscopy (NCL), S-MAP evaluates the upper abdomen (diaphragm, gallbladder), lower abdomen (cecum, appendix), and all pelvic structures (anterior and posterior cul-de-sac) in the same reproducible sequence every time. Dr. Whittaker presented a case series at AAGL 2024 demonstrating that NCL/S-MAP led to the incidental diagnosis and curative treatment of four rare cancers during fertility/pain surgeries by a single surgeon over three years.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_semen-analysis', 'semen-analysis', 'Semen Analysis', 'IV', 10, '<p><strong>The primary diagnostic test for male factor infertility,</strong> evaluating sperm concentration (count), motility, morphology (shape), volume, and other parameters. A normal semen analysis does not exclude male factor, as it does not assess sperm DNA integrity; additional testing (see Sperm DNA Fragmentation Index) may be warranted in cases of unexplained infertility or recurrent miscarriage.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sperm-dna-fragmentation', 'sperm-dna-fragmentation', 'Sperm DNA Fragmentation Index (DFI)', 'IV', 11, '<p><strong>A measure of the proportion of sperm with damaged or fragmented DNA.</strong> High SDF is associated with poor reproductive outcomes including reduced natural conception rates, failed IUI, increased miscarriage risk, and impaired embryo development. Standard semen analysis does not assess DNA integrity, making SDF testing an important adjunct in evaluating unexplained infertility, recurrent pregnancy loss, and repeated ART failure. Treatment strategies include lifestyle modification, antioxidant therapy, varicocele repair, and in select cases, testicular sperm retrieval.<sup><a href="#ref-19">19</a></sup><sup><a href="#ref-20">20</a></sup><sup><a href="#ref-21">21</a></sup><sup><a href="#ref-22">22</a></sup></p>', 'DFI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_era', 'era', 'Endometrial Receptivity Analysis (ERA)', 'IV', 12, '<p><strong>A molecular diagnostic test that evaluates gene expression in an endometrial biopsy sample</strong> to determine the personalized "window of implantation" (WOI), the period during which the endometrium is most receptive to embryo implantation. The ERA analyzes the expression profile of 236 to 238 genes related to endometrial receptivity status. In approximately 20 to 25% of women with recurrent implantation failure, the WOI is displaced from the standard timing. A study of 3,605 patients found that clinical pregnancy rate and live birth rate improved after personalized embryo transfer guided by ERA results, particularly in recurrent implantation failure patients.<sup><a href="#ref-23">23</a></sup><sup><a href="#ref-24">24</a></sup><sup><a href="#ref-25">25</a></sup></p>', 'ERA', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cd138', 'cd138', 'CD138 (Syndecan-1) Immunohistochemistry', 'IV', 13, '<p><strong>A staining technique used on endometrial biopsy specimens to identify plasma cells,</strong> which are pathognomonic (definitively diagnostic) for chronic endometritis. CD138 IHC is more sensitive than routine histology alone for detecting chronic endometritis and is the current standard for diagnosis when chronic endometritis is suspected.<sup><a href="#ref-26">26</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_emma-alice', 'emma-alice', 'EMMA / ALICE (Endometrial Microbiome Testing)', 'IV', 14, '<p><strong>Molecular diagnostic tests that analyze the endometrial microbiome from a biopsy sample.</strong> EMMA (Endometrial Microbiome Metagenomic Analysis) measures the abundance and composition of endometrial bacteria, including the proportion of Lactobacillus (considered protective) and the presence of dysbiotic organisms. ALICE (Analysis of Infectious Chronic Endometritis) identifies pathogenic bacteria specifically associated with chronic endometritis. EMMA and ALICE are often ordered together with <a href="#era">Endometrial Receptivity Analysis (ERA)</a> from a single biopsy as an "EndomeTRIO" panel. Microbiome-targeted probiotic and antibiotic treatments guided by these results have been studied as adjuncts for women with recurrent implantation failure and recurrent pregnancy loss, though evidence quality varies across studies.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pgt-a', 'pgt-a', 'PGT-A (Preimplantation Genetic Testing for Aneuploidy)', 'IV', 15, '<p><strong>A laboratory test performed on an embryo biopsy during IVF to screen for chromosomal aneuploidy before transfer.</strong> Formerly called PGS (preimplantation genetic screening), PGT-A is marketed as a tool to improve IVF success rates by selecting only euploid embryos for transfer. Evidence for routine use is mixed: randomized trials have not shown a significant improvement in cumulative live-birth rates for women under 35, and concerns have been raised about discarding mosaic embryos that may produce healthy pregnancies. PGT-A is specific to IVF and is not part of RRM, which does not involve embryo selection, embryo biopsy, or embryo disposition decisions.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_excision-surgery', 'excision-surgery', 'Excision Surgery (for Endometriosis)', 'V', 0, '<p><strong>The surgical removal of endometriotic tissue by cutting it out, as opposed to ablation (burning/destroying it superficially).</strong> Considered the preferred surgical approach in RRM for endometriosis. A 2022 cohort study of 232 patients showed that excision improved outcomes across all 63 symptom measures evaluated (ranging from 28 to 46% improvement), while ablation only marginally improved period pain (11.3%) and heavy periods (8.5%) and worsened status in 23 of 24 quality-of-life measures. A meta-analysis found significantly greater reduction in dysmenorrhea (MD=0.99), dyschezia, and chronic pelvic pain with excision compared to ablation at 12 months.<sup><a href="#ref-27">27</a></sup><sup><a href="#ref-28">28</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fulguration-ablation', 'fulguration-ablation', 'Fulguration / Ablation / Cauterization (Endometriosis)', 'V', 1, '<p><strong>Superficial destruction of tissue using heat, electrical energy, or laser vaporization.</strong> As applied to endometriosis, this approach destroys the visible surface of lesions without removing the tissue or underlying disease. Evidence consistently demonstrates it is less effective than excision for symptom resolution, quality-of-life improvement, and fertility outcomes, and is associated with higher recurrence rates. Not preferred in RRM.<sup><a href="#ref-29">29</a></sup><sup><a href="#ref-27">27</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_adhesiolysis', 'adhesiolysis', 'Adhesiolysis', 'V', 2, '<p><strong>Surgical division and removal of adhesions (pelvic scar tissue).</strong> In RRM and NaPro Surgery, adhesiolysis is performed meticulously, with hemostasis and anti-adhesion barrier placement to minimize adhesion reformation.<sup><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_anti-adhesion-barriers', 'anti-adhesion-barriers', 'Anti-Adhesion Barriers', 'V', 3, '<p><strong>Materials placed during surgery to physically separate tissue surfaces during the healing period, reducing adhesion formation.</strong> In NaPro Surgery, Gore-Tex membrane (expanded polytetrafluoroethylene) has been used extensively, with published results showing dramatic reductions in adhesion reformation scores over time.<sup><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_tubal-ligation-reversal', 'tubal-ligation-reversal', 'Tubo-tubal Anastomosis (Tubal Ligation Reversal)', 'V', 4, '<p><strong>Microsurgical reconnection of the fallopian tube segments following prior tubal ligation ("tubes tied"), allowing natural conception to resume.</strong> Can be performed via laparoscopy, robotic assistance, or mini-laparotomy. Pregnancy rates after tubal reversal using microsurgical techniques range from 57% to 84%. A large series found that women under 30 with ring/clip sterilization reversals achieved an 88% pregnancy rate. Success depends most strongly on the woman''s age at time of reversal and the remaining tube length after reconstruction.<sup><a href="#ref-30">30</a></sup><sup><a href="#ref-31">31</a></sup><sup><a href="#ref-32">32</a></sup><sup><a href="#ref-33">33</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_vasectomy-reversal', 'vasectomy-reversal', 'Vasectomy Reversal (Vasovasostomy / Vasoepididymostomy)', 'V', 5, '<p><strong>Microsurgical reconnection of the vas deferens after prior vasectomy, restoring the potential for natural conception.</strong> Vasovasostomy joins the two cut ends of the vas deferens and is the standard procedure. Vasoepididymostomy, a more technically demanding variant, is required when a secondary epididymal blockage has developed upstream, which is more likely with obstructive intervals greater than 10 to 15 years. Patency rates (return of sperm to the ejaculate) exceed 90% for vasovasostomy performed by experienced microsurgeons; pregnancy rates vary by obstructive interval, female partner age, and surgical technique. Vasectomy reversal is the RRM-aligned restorative alternative to surgical sperm retrieval combined with IVF/ICSI for couples seeking further pregnancies after prior vasectomy, treating the obstruction rather than bypassing it.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fallopian-tube-recanalization', 'fallopian-tube-recanalization', 'Fallopian Tube Recanalization (Cannulation)', 'V', 6, '<p><strong>A procedure to open proximal (near the uterus) fallopian tube blockages through transcervical catheter passage, without open surgery.</strong> Often performed in conjunction with HSG. Can be done in an office or interventional radiology setting.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_neosalpingostomy', 'neosalpingostomy', 'Neosalpingostomy / Fimbrioplasty', 'V', 7, '<p><strong>Laparoscopic surgical repair of distal (fimbrial end) fallopian tube damage,</strong> typically caused by pelvic inflammatory disease or prior infection. Neosalpingostomy creates a new opening in a completely blocked tube (hydrosalpinx), while fimbrioplasty reconstructs and opens a partially obstructed or agglutinated fimbrial end.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_lowr', 'lowr', 'Laparoscopic Ovarian Wedge Resection (LOWR)', 'V', 8, '<p><strong>A surgical procedure for select PCOS cases, involving removal of a wedge of androgen-producing ovarian cortex to normalize hormonal balance and restore ovulation.</strong> Using microsurgical laser techniques, NaPro wedge resection has achieved approximately 70% pregnancy rates, over twice as effective as standard clomiphene citrate treatment (~30%) and higher than reported IVF success rates in PCOS (~23%). This surgical solution restores regular ovulation and does not carry the risk of ovarian hyperstimulation.<sup><a href="#ref-10">10</a></sup></p>', 'LOWR', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_isthmocele-repair-hysteroscopic', 'isthmocele-repair-hysteroscopic', 'Isthmocele Repair (Hysteroscopic)', 'V', 9, '<p><strong>Hysteroscopic treatment of a cesarean scar defect (isthmocele) by shaving and cauterizing the defect internally,</strong> reducing the depth of the niche and improving drainage of retained blood. Best suited for symptomatic patients (primarily bleeding complaints) with a residual myometrial wall thickness &gt;5mm who do not desire future pregnancy. Associated with faster recovery but lower rates of complete bleeding resolution and does not restore wall integrity for future pregnancy.<sup><a href="#ref-34">34</a></sup><sup><a href="#ref-15">15</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_isthmocele-repair-laparoscopic', 'isthmocele-repair-laparoscopic', 'Isthmocele Repair (Laparoscopic)', 'V', 10, '<p><strong>Laparoscopic excision of the defect with multi-layer reconstruction of the uterine muscular wall.</strong> Preferred when fertility preservation is desired or when residual myometrial thickness is &lt;5mm. Restores wall integrity for safer future pregnancy and is more likely to resolve bleeding symptoms. Longer recovery than hysteroscopic repair. Combined laparoscopic-hysteroscopic approaches are used for complex cases.<sup><a href="#ref-16">16</a></sup><sup><a href="#ref-15">15</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_myomectomy', 'myomectomy', 'Myomectomy', 'V', 11, '<p><strong>Surgical removal of uterine fibroids (leiomyomas) while preserving the uterus.</strong> Can be performed hysteroscopically (for submucosal fibroids), laparoscopically, robotically, or via laparotomy depending on fibroid type, size, and number. RRM prefers fertility-sparing myomectomy over hysterectomy when fibroids are contributing to infertility or pregnancy loss.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_microsurgery', 'microsurgery', 'Microsurgery', 'V', 12, '<p><strong>Surgical technique performed under microscopic magnification using fine instruments and sutures</strong> (often 6-0 to 9-0 gauge), essential for tubal anastomosis in ligation reversal and repair. Microsurgical principles include minimal tissue handling, precise hemostasis, tension-free anastomosis, and meticulous layer-by-layer closure.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_mini-laparotomy', 'mini-laparotomy', 'Mini-laparotomy', 'V', 13, '<p><strong>A small (approximately 3 to 5 cm) "bikini line" incision surgery,</strong> sometimes used as an alternative to laparoscopy for procedures such as tubal ligation reversal in appropriately selected patients. Offers a smaller scar and reduced anesthesia risk compared to traditional open surgery.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_infertility', 'infertility', 'Infertility', 'VI', 0, '<p><strong>Clinically defined as failure to achieve pregnancy after 12 months of regular unprotected intercourse (6 months for women 35 years and older).</strong> In the RRM framework, infertility is understood as a symptom of one or more identifiable, underlying, treatable conditions, not a diagnosis in itself. Approximately 15% of couples worldwide are affected.<sup><a href="#ref-4">4</a></sup><sup><a href="#ref-35">35</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_rpl', 'rpl', 'Recurrent Pregnancy Loss (RPL)', 'VI', 1, '<p><strong>Typically defined as two or more consecutive clinical pregnancy losses before 20 weeks of gestation.</strong> Assessment includes peripheral karyotype analysis of both partners, antiphospholipid antibody testing, uterine anatomical evaluation (SHG, HSG, or hysteroscopy), thyroid and prolactin screening, and evaluation for hereditary thrombophilias. RRM pursues identification of underlying conditions including hormonal (progesterone deficiency, thyroid dysfunction), anatomical (isthmocele, septum, fibroids), immunologic (APS, NK cell activity), and metabolic factors.<sup><a href="#ref-36">36</a></sup><sup><a href="#ref-37">37</a></sup></p>', 'RPL', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometriosis', 'endometriosis', 'Endometriosis', 'VI', 2, '<p><strong>A chronic inflammatory condition in which endometrial-like tissue is found outside the uterine cavity</strong>, most commonly on the ovaries, fallopian tubes, pelvic peritoneum, and rectovaginal septum. Affects approximately 1 in 10 women of reproductive age. RRM''s preferred treatment is laparoscopic excision surgery, which demonstrates significantly greater improvement across all symptom domains (28 to 46% improvement range) compared to ablation, which failed to improve most symptoms and worsened quality of life in multiple measures. A key RRM principle is that hormonal suppression post-surgery (e.g., oral contraceptive pills) masks ongoing disease activity without treating the condition.<sup><a href="#ref-28">28</a></sup><sup><a href="#ref-27">27</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometrioma', 'endometrioma', 'Endometrioma', 'VI', 3, '<p><strong>An ovarian cyst formed by endometriosis, filled with old menstrual blood</strong> (colloquially called a "chocolate cyst"). Endometriomas reduce ovarian reserve and impair oocyte quality. Surgical management with excisional cystectomy is generally preferred over drainage and ablation, though ovarian reserve impact of surgery must be considered.<sup><a href="#ref-38">38</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pcos', 'pcos', 'PCOS (Polycystic Ovary Syndrome)', 'VI', 4, '<p><strong>A complex hormonal and metabolic disorder characterized by ovulatory dysfunction, hyperandrogenism (elevated androgens causing acne, hirsutism), and/or polycystic ovarian morphology on ultrasound.</strong> Insulin resistance and visceral adiposity are key pathophysiologic drivers, irrespective of obesity. RRM''s multi-factorial approach includes lifestyle modification (5% weight loss can restore ovulation), insulin sensitization (metformin, myo-inositol), cycle charting and ovulation monitoring, targeted hormonal support, and in select cases, laparoscopic ovarian wedge resection.<sup><a href="#ref-39">39</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pcos-phenotypes', 'pcos-phenotypes', 'PCOS Phenotypes (Rotterdam A through D)', 'VI', 5, '<p><strong>PCOS is diagnosed when two of three Rotterdam criteria are met: ovulatory dysfunction, clinical or biochemical hyperandrogenism, and polycystic ovarian morphology on ultrasound.</strong> Four phenotypes arise based on which two or three criteria are present:</p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_myo-inositol', 'myo-inositol', 'Myo-Inositol', 'VI', 6, '<p><strong>A naturally occurring carbocyclic sugar that acts as an insulin sensitizer and secondary messenger in FSH signaling.</strong> Used as a supplement in PCOS management. Evidence shows myo-inositol improves ovarian function, oocyte maturity rates, fertilization rates, and metabolic parameters (LH, FSH, HOMA-IR) in women with PCOS. A 2025 meta-analysis found statistically significant improvement in MII oocyte rate and fertilization rate, though evidence for clinical pregnancy rate improvement remains less conclusive.<sup><a href="#ref-40">40</a></sup><sup><a href="#ref-41">41</a></sup><sup><a href="#ref-42">42</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_isthmocele', 'isthmocele', 'Uterine Isthmocele (Cesarean Scar Defect / Uterine Niche)', 'VI', 7, '<p><strong>A myometrial defect (a pouch or indentation) in the anterior wall of the lower uterine segment (isthmus) at the site of a previous cesarean section scar,</strong> representing discontinuity of the myometrium. Caused by incomplete or defective healing of the uterine closure at the time of cesarean delivery. The defect creates a reservoir in which menstrual blood pools, then drains slowly, resulting in characteristic post-menstrual brown spotting. The retained blood creates a hostile microenvironment for sperm and may impair implantation, contributing to secondary infertility and increased miscarriage risk when the wall is thin. Prevalence is approximately 20% or more in women with prior cesarean deliveries.<sup><a href="#ref-15">15</a></sup><sup><a href="#ref-16">16</a></sup><sup><a href="#ref-34">34</a></sup></p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_luteal-phase-deficiency', 'luteal-phase-deficiency', 'Luteal Phase Deficiency (LPD)', 'VI', 8, '<p><strong>A reproductive condition characterized by inadequate progesterone production or insufficient duration of the luteal phase,</strong> impairing endometrial preparation for implantation and early pregnancy support. Causes include impaired follicular development leading to insufficient corpus luteum formation, hypothyroidism, hyperprolactinemia, and GnRH pulsatility disruption. NaPro diagnosis is based on cycle-timed progesterone measurements. Treatment involves ovulation induction (to optimize follicular development and subsequent corpus luteum function) and/or progesterone supplementation beginning 3 to 4 days after the LH surge.<sup><a href="#ref-44">44</a></sup><sup><a href="#ref-45">45</a></sup></p>', 'LPD', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_luteal-phase', 'luteal-phase', 'Luteal Phase (LP)', 'VI', 9, '<p><strong>The period of the menstrual cycle following ovulation (post-peak) and preceding menstruation or implantation,</strong> typically lasting 12 to 16 days. During the luteal phase, the corpus luteum secretes progesterone to prepare the endometrium for potential implantation. A short luteal phase (&lt;10 days) is associated with infertility and impaired endometrial maturation.<sup><a href="#ref-44">44</a></sup></p>', 'LP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_corpus-luteum', 'corpus-luteum', 'Corpus Luteum (CL)', 'VI', 10, '<p><strong>A temporary endocrine structure formed from the ruptured ovarian follicle after ovulation.</strong> The corpus luteum produces progesterone and estradiol during the luteal phase. If pregnancy occurs, hCG from the implanting trophoblast rescues the corpus luteum, sustaining progesterone production until the placenta takes over (approximately 10 weeks). Inadequate CL function is a mechanism of LPD.<sup><a href="#ref-44">44</a></sup></p>', 'CL', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_luf-syndrome', 'luf-syndrome', 'Luteinized Unruptured Follicle (LUF) Syndrome', 'VI', 11, '<p><strong>A condition in which the dominant follicle reaches maturity and undergoes apparent luteinization (progesterone production begins) without actually releasing the egg</strong> (anovulation occurs despite apparent cycle regularity). LUF can cause unexplained infertility despite normal menstrual cycles and is identified by follicle tracking ultrasound showing a persistent follicle that fails to collapse at expected ovulation time.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_anovulatory-cycles', 'anovulatory-cycles', 'Anovulatory Cycles', 'VI', 12, '<p><strong>Menstrual cycles in which ovulation does not occur,</strong> potentially presenting as apparently normal or irregular periods. Associated with PCOS, hypothalamic dysfunction, excessive exercise, low body weight, elevated prolactin, or thyroid disorders. Identified through cycle charting (absence of post-peak phase), follicle tracking, or mid-luteal progesterone testing.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_shortened-luteal-phase', 'shortened-luteal-phase', 'Shortened Luteal Phase', 'VI', 13, '<p><strong>A luteal phase &lt;10 days in duration,</strong> associated with inadequate progesterone production, impaired endometrial maturation, and reduced fertility. Observed in conditions of hormonal imbalance, ovulation induction side effects, and physical stress.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_tubal-factor-infertility', 'tubal-factor-infertility', 'Tubal Factor Infertility', 'VI', 14, '<p><strong>Infertility attributed to blocked, damaged, or functionally compromised fallopian tubes.</strong> Affects approximately 25 to 30% of women with infertility. Causes include prior pelvic inflammatory disease (PID), chlamydia, endometriosis, pelvic adhesions, or prior tubal surgery. RRM offers corrective surgical alternatives to IVF: fallopian tube recanalization for proximal blockage, tubo-tubal anastomosis for mid-segment disease, and neosalpingostomy/fimbrioplasty for distal disease.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hydrosalpinx', 'hydrosalpinx', 'Hydrosalpinx', 'VI', 15, '<p><strong>A fluid-filled, distended, obstructed fallopian tube</strong>, typically the result of prior infection or endometriosis causing complete distal tubal occlusion. Hydrosalpinges are associated with reduced IVF success rates (the fluid may be embryotoxic). RRM options include neosalpingostomy (opening and repairing the tube) when tube quality is adequate, or salpingectomy if repair is not feasible.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fallopian-tube-anatomy', 'fallopian-tube-anatomy', 'Fallopian Tube Anatomy Reference', 'VI', 16, '<p><strong>The fallopian tube has four anatomical segments, each relevant to RRM diagnosis and surgery:</strong><sup><a href="#ref-46">46</a></sup><sup><a href="#ref-47">47</a></sup></p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pelvic-adhesions', 'pelvic-adhesions', 'Pelvic Adhesions (Scar Tissue)', 'VI', 17, '<p><strong>Bands of fibrous tissue that form between pelvic structures following inflammation, infection, endometriosis, or prior surgery.</strong> Adhesions can distort pelvic anatomy, restrict tube and ovarian mobility, cause chronic pelvic pain, and impair fertility. RRM treatment involves meticulous laparoscopic adhesiolysis with anti-adhesion barrier placement.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_adenomyosis', 'adenomyosis', 'Adenomyosis', 'VI', 18, '<p><strong>A condition in which endometrial-like glands and stroma are present within the myometrium (uterine muscle wall),</strong> causing the uterus to enlarge and the junctional zone (the inner myometrium) to thicken. Adenomyosis is associated with heavy, painful periods and impaired fertility. A meta-analysis found women with adenomyosis had a 28% decreased probability of clinical pregnancy via IVF/ICSI compared to women without it, and higher miscarriage rates (OR 2.17). RRM approaches include hormonal management, and in selected cases, surgical resection of focal lesions.<sup><a href="#ref-48">48</a></sup><sup><a href="#ref-49">49</a></sup><sup><a href="#ref-50">50</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_uterine-fibroids', 'uterine-fibroids', 'Uterine Fibroids (Leiomyomas)', 'VI', 19, '<p><strong>Benign smooth muscle tumors of the uterus.</strong> Classification by location significantly affects fertility impact:</p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_uterine-septum', 'uterine-septum', 'Uterine Septum', 'VI', 20, '<p><strong>A congenital structural abnormality in which a fibromuscular wall (septum) divides part or all of the uterine cavity.</strong> Associated with increased risk of miscarriage (due to poor septum vascularization impairing implantation) and preterm labor. Treated hysteroscopically by incising and resecting the septum.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ashermans-syndrome', 'ashermans-syndrome', 'Intrauterine Adhesions (Asherman''s Syndrome)', 'VI', 21, '<p><strong>Scar tissue within the uterine cavity, typically following uterine trauma</strong> (e.g., D&amp;C, myomectomy, infection). Ranges from mild adhesions to obliteration of the cavity. Diagnosed by SIS, HSG, or hysteroscopy. Treated by hysteroscopic adhesiolysis with post-operative estrogen therapy to promote re-epithelialization.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_chronic-endometritis', 'chronic-endometritis', 'Chronic Endometritis (CE)', 'VI', 22, '<p><strong>A persistent, low-grade inflammatory condition of the endometrial lining caused by abnormal colonization of the endometrium by bacteria</strong> (e.g., Enterococcus, E. coli, Streptococcus). Often subclinical (no obvious symptoms). CE is significantly associated with recurrent implantation failure and recurrent pregnancy loss. Diagnosed by office hysteroscopy (strawberry-pattern micropolypoid endometrium) confirmed by CD138 immunohistochemistry on endometrial biopsy. Treated with targeted antibiotics (typically doxycycline, amoxicillin, or based on culture). A cohort study showed the biopsy/treatment group had significantly higher chances of pregnancy (HR 2.28) and live birth (HR 2.76) compared to hysteroscopy-only controls.<sup><a href="#ref-51">51</a></sup><sup><a href="#ref-26">26</a></sup></p>', 'CE', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_aps', 'aps', 'Antiphospholipid Syndrome (APS)', 'VI', 23, '<p><strong>An autoimmune condition in which antiphospholipid antibodies</strong> (including lupus anticoagulant, anticardiolipin antibodies (aCL), and anti-beta-2 glycoprotein I antibodies) cause a hypercoagulable state that can result in thrombosis and pregnancy complications including recurrent miscarriage, fetal loss, and stillbirth. Diagnosis requires both clinical criteria (vascular thrombosis or pregnancy morbidity) and laboratory criteria (confirmed antibodies on two occasions 12 or more weeks apart). RRM treatment: low-dose aspirin initiated preconceptionally, plus prophylactic-dose heparin (LMWH) from a positive pregnancy test through delivery. Multiple guidelines (EULAR, ESHRE, ACCP, ACOG) support this protocol.<sup><a href="#ref-52">52</a></sup><sup><a href="#ref-36">36</a></sup></p>', 'APS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_autoimmune-thrombophilic', 'autoimmune-thrombophilic', 'Autoimmune/Thrombophilic Disorders (as RPL Causes)', 'VI', 24, '<p><strong>Beyond APS, RRM evaluates for inherited thrombophilias</strong> (Factor V Leiden, prothrombin mutation, protein C/S deficiency), natural killer (NK) cell dysregulation, and systemic autoimmune conditions (antithyroid antibodies, antinuclear antibodies) in women with RPL. Assessment guides individualized medical therapy.<sup><a href="#ref-37">37</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_methylated-folate', 'methylated-folate', 'Methylated Folate (L-Methylfolate) and MTHFR', 'VI', 25, '<p><strong>The biologically active form of folate (5-methyltetrahydrofolate, 5-MTHF) that participates directly in homocysteine remethylation, DNA synthesis, and methylation reactions critical to early embryonic development.</strong> Synthetic folic acid (the form in most prenatal vitamins and fortified foods) requires enzymatic conversion by methylenetetrahydrofolate reductase (MTHFR) to become biologically active. Common MTHFR gene variants (C677T and A1298C) reduce enzyme activity and can impair folate metabolism, potentially contributing to elevated homocysteine, thrombophilic risk, and recurrent pregnancy loss in affected individuals. RRM protocols often specify L-methylfolate rather than folic acid preconceptionally, particularly for women with known MTHFR variants, recurrent miscarriage, or elevated homocysteine levels.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_varicocele', 'varicocele', 'Varicocele', 'VI', 26, '<p><strong>An abnormal dilation of the veins within the scrotum (pampiniform plexus),</strong> present in 15% of the male population and in approximately 35% of men evaluated for infertility. Varicoceles raise scrotal temperature and increase oxidative stress, impairing spermatogenesis and increasing sperm DNA fragmentation. Varicocele repair (varicocelectomy) results in significant improvement in semen parameters in 60 to 80% of men, with natural pregnancy rates of 43% at one year and 69% at two years when female factors are excluded. Microsurgical subinguinal varicocelectomy is the preferred technique, associated with the highest spontaneous pregnancy rates and lowest complication rates.<sup><a href="#ref-53">53</a></sup><sup><a href="#ref-54">54</a></sup><sup><a href="#ref-55">55</a></sup><sup><a href="#ref-56">56</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_male-factor-infertility', 'male-factor-infertility', 'Male Factor Infertility', 'VI', 27, '<p><strong>Infertility attributable to male reproductive factors, estimated to contribute to approximately 50% of infertility cases when assessed comprehensively.</strong> RRM evaluates male partners with semen analysis, sperm DNA fragmentation testing, hormonal testing, and where indicated, surgical evaluation (varicocele assessment). Treatments include varicocele repair, lifestyle modification, antioxidant therapy, hormonal correction, and in severe cases (azoospermia), microsurgical sperm retrieval.<sup><a href="#ref-35">35</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_oat-syndrome', 'oat-syndrome', 'Oligospermia / Asthenospermia / Teratospermia', 'VI', 28, '<p><strong>Reduced sperm parameters defined by WHO reference values:</strong></p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_azoospermia', 'azoospermia', 'Azoospermia', 'VI', 29, '<p><strong>Complete absence of sperm in the ejaculate.</strong> Classified as:</p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_oxidative-stress', 'oxidative-stress', 'Oxidative Stress / Reactive Oxygen Species (ROS)', 'VI', 30, '<p><strong>An imbalance between pro-oxidant species (ROS, reactive nitrogen species) and antioxidant defenses.</strong> At physiological levels, ROS play important roles in folliculogenesis, oocyte maturation, capacitation, and embryo development. Excess ROS, however, damages sperm DNA, impairs sperm motility, disrupts oocyte quality, damages embryos, and is linked to endometriosis, PCOS, unexplained infertility, recurrent miscarriage, and preeclampsia. RRM addresses oxidative stress through targeted antioxidant supplementation (vitamin C, E, CoQ10, zinc, selenium, L-carnitine, N-acetylcysteine), lifestyle modification (smoking cessation, weight management), and treatment of underlying conditions.<sup><a href="#ref-57">57</a></sup><sup><a href="#ref-58">58</a></sup><sup><a href="#ref-35">35</a></sup></p>', 'ROS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sperm-dna-fragmentation-extended', 'sperm-dna-fragmentation-extended', 'Sperm DNA Fragmentation Index (DFI): Extended', 'VI', 31, '<p><strong>High DFI (generally defined as &gt;25 to 30%) is independently associated with poor reproductive outcomes,</strong> including failed natural conception and IUI, and is a significant predictor of miscarriage. Treatment strategies in RRM include: antioxidant supplementation (reduces DFI and improves pregnancy rates); varicocele repair (meta-analysis: 3.37% mean DFI reduction post-repair); lifestyle changes (smoking cessation, weight optimization, stress reduction); treating genital tract infections; and shortened ejaculatory abstinence periods. Testicular sperm extraction yields sperm with lower DFI than ejaculated sperm in severe cases.<sup><a href="#ref-20">20</a></sup><sup><a href="#ref-21">21</a></sup><sup><a href="#ref-19">19</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hormonal-abnormalities', 'hormonal-abnormalities', 'Hormonal Abnormalities', 'VI', 32, '<p><strong>Imbalances disrupting the menstrual cycle, ovulation, or early pregnancy.</strong> RRM diagnoses these through cycle-timed blood tests guided by fertility charting. Key hormones evaluated include:</p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hypothyroidism', 'hypothyroidism', 'Hypothyroidism / Subclinical Hypothyroidism', 'VI', 33, '<p><strong>Deficiency of thyroid hormone, most commonly due to autoimmune Hashimoto''s thyroiditis in iodine-sufficient regions.</strong> Even subclinical hypothyroidism (elevated TSH with normal free T4) is associated with increased miscarriage risk, impaired fertility, and potential adverse pregnancy outcomes. RRM screens thyroid function and optimizes thyroid status before and during attempts at conception.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hyperprolactinemia', 'hyperprolactinemia', 'Hyperprolactinemia', 'VI', 34, '<p><strong>Elevated serum prolactin levels, which suppress hypothalamic GnRH pulsatility, thereby reducing LH and FSH secretion.</strong> Results in ovulatory dysfunction, luteal phase insufficiency, and impaired fertility. Common causes include pituitary microadenoma (prolactinoma), hypothyroidism, and medications. Treated with dopamine agonists (cabergoline, bromocriptine) or management of the underlying cause.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_poi', 'poi', 'Premature Ovarian Insufficiency (POI)', 'VI', 35, '<p><strong>Loss of normal ovarian function before age 40,</strong> resulting in irregular or absent menstruation, infertility, and hormonal deficiencies mimicking menopause. Affects approximately 1% of women under 40. Causes include autoimmune, genetic (fragile X premutation), iatrogenic (chemotherapy, radiation), and idiopathic. RRM evaluation and management includes hormone replacement therapy, fertility-preservation strategies, and treatment of underlying autoimmune conditions.<sup><a href="#ref-3">3</a></sup></p>', 'POI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_dor', 'dor', 'Diminished Ovarian Reserve (DOR)', 'VI', 36, '<p><strong>A reduction in the quantity (and sometimes quality) of oocytes in the ovaries, leading to decreased fertility potential.</strong> Diagnosed by elevated FSH, low AMH, and low antral follicle count (AFC) on ultrasound. DOR is age-related but can occur prematurely. RRM takes an aggressive diagnostic approach, evaluating for autoimmune, mitochondrial, inflammatory, and lifestyle contributors.<sup><a href="#ref-3">3</a></sup></p>', 'DOR', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_insulin-resistance', 'insulin-resistance', 'Insulin Resistance / Metabolic Dysfunction', 'VI', 37, '<p><strong>A state of impaired cellular response to insulin, common in PCOS (present in 50 to 70% of cases)</strong> and an independent contributor to ovulatory dysfunction, infertility, and miscarriage. RRM addresses through dietary modification (low glycemic index diet), exercise, targeted supplementation (myo-inositol, alpha-lipoic acid, CoQ10), and medication (metformin) when indicated.<sup><a href="#ref-39">39</a></sup><sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_secondary-infertility', 'secondary-infertility', 'Secondary Infertility', 'VI', 38, '<p><strong>Difficulty conceiving after a prior pregnancy.</strong> RRM re-evaluates comprehensively for new or evolving conditions, including C-section scar isthmocele, new-onset endometriosis or adhesions, chronic endometritis, postpartum thyroiditis, or hormonal shifts.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_unexplained-infertility', 'unexplained-infertility', 'Unexplained Infertility', 'VI', 39, '<p><strong>A clinical label given when no cause is identified through standard evaluation.</strong> RRM does not accept this as a final diagnosis but pursues deeper investigation including cycle-timed hormone panels, advanced sperm testing (SDF), chronic endometritis screening, immunologic testing, and laparoscopic assessment for subtle pelvic pathology.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_time-to-pregnancy', 'time-to-pregnancy', 'Time to Pregnancy (TTP)', 'VI', 40, '<p><strong>The number of menstrual cycles or months required to achieve a clinical pregnancy in a couple attempting conception.</strong> In the general fertile population, approximately 80% of couples conceive within six cycles and 90% within twelve cycles. TTP is an important framing concept in RRM: procedural approaches are often reported as per-cycle success rates, whereas RRM is evaluated by cumulative outcomes across the full course of diagnosis and treatment. Published NaProTECHNOLOGY cohort studies report cumulative live-birth rates at 24 and 36 months, reflecting the restorative time horizon in which underlying conditions are corrected and fertility resumes naturally.<sup><a href="#ref-10">10</a></sup><sup><a href="#ref-11">11</a></sup></p>', 'TTP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cervical-factor-infertility', 'cervical-factor-infertility', 'Cervical Factor Infertility', 'VI', 41, '<p><strong>Impaired cervical mucus production or quality, reducing sperm survival and transport.</strong> Contributing factors include low estrogen, prior cervical procedures (LEEP, cone biopsy), cervical inflammation, or mucus antibodies. RRM optimizes cervical mucus through hormonal support of estrogen adequacy and treatment of underlying hormonal deficiencies.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_poor-cervical-mucus', 'poor-cervical-mucus', 'Poor Cervical Mucus Production', 'VI', 42, '<p><strong>Cervical mucus that is insufficient in quantity, too thick, or does not exhibit fertile-quality characteristics</strong> (clear, stretchy, lubricative) near ovulation. Fertile mucus creates a protective environment for sperm, filtering defective sperm and providing a reservoir that sustains sperm for up to 5 days. Poor mucus production reduces the effective fertile window and impairs sperm ascent.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometrial-thickness', 'endometrial-thickness', 'Endometrial Thickness', 'VI', 43, '<p><strong>The measurement of the uterine lining as assessed by transvaginal ultrasound.</strong> Optimal endometrial thickness for implantation is generally 7 to 8 mm or more with a trilaminar (three-layer) pattern. Thin endometrium is associated with reduced implantation rates and is investigated for causes including prior uterine surgery, estrogen deficiency, poor blood flow, and Asherman''s syndrome.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometrial-hyperplasia', 'endometrial-hyperplasia', 'Endometrial Hyperplasia', 'VI', 44, '<p><strong>A pathologic overgrowth of the endometrium characterized by increased number and crowding of endometrial glands, usually caused by prolonged estrogen exposure without sufficient progesterone (unopposed estrogen).</strong> This condition is not cancer, but some forms are precancerous and can progress to endometrial adenocarcinoma if untreated. Classified as "without atypia" (lower risk) or "atypical" (endometrial intraepithelial neoplasia, higher cancer risk). Often presents with abnormal uterine bleeding: heavy, frequent, irregular, or postmenopausal.</p>
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_window-of-implantation', 'window-of-implantation', 'Window of Implantation (WOI)', 'VI', 45, '<p><strong>The hormonally determined period during the secretory phase of the menstrual cycle</strong> (approximately cycle days 19 to 23 in a standard 28-day cycle) during which the endometrium is maximally receptive to embryo implantation. The WOI is precisely regulated by estrogen and progesterone and is displaced in approximately 20 to 25% of women with recurrent implantation failure, identifiable via ERA testing.<sup><a href="#ref-24">24</a></sup><sup><a href="#ref-23">23</a></sup></p>', 'WOI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_postpartum-fertility', 'postpartum-fertility', 'Postpartum Fertility Issues', 'VI', 46, '<p><strong>Fertility challenges arising in the postpartum period,</strong> including lactational amenorrhea (anovulation during breastfeeding due to prolactin elevation), retained placenta fragments, postpartum thyroiditis, hormonal dysregulation, and uterine scar defects (isthmocele from cesarean delivery). RRM offers specialized postpartum evaluations to identify and address these causes.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_chronic-pelvic-pain', 'chronic-pelvic-pain', 'Chronic Pelvic Pain (CPP)', 'VI', 47, '<p><strong>Pelvic pain lasting 6 months or more,</strong> often involving multiple overlapping causes: gynecologic (endometriosis, adenomyosis, pelvic adhesions), musculoskeletal, urologic (interstitial cystitis), gastrointestinal, neuropathic, and psychosocial. RRM addresses gynecologic causes surgically (excision, adhesiolysis) while recognizing the multidimensional nature of CPP and coordinating interdisciplinary care.</p>', 'CPP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_reproductive-endocrinology', 'reproductive-endocrinology', 'Reproductive Endocrinology', 'VII', 0, '<p><strong>The study of hormonal regulation of reproduction, encompassing the hypothalamic-pituitary-gonadal axis and its downstream effects on ovulation, implantation, and pregnancy maintenance.</strong> In RRM, reproductive endocrinology is practiced with cycle-timed hormone evaluation (blood draws ordered at specific cycle phases identified by charting) rather than single random draws that miss dynamic hormonal patterns. This discipline is core to all RRM approaches, providing the diagnostic foundation for targeted medical treatment.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_reproductive-immunology', 'reproductive-immunology', 'Reproductive Immunology', 'VII', 1, '<p><strong>The investigation of the immune system''s role in implantation failure, recurrent miscarriage, and conditions such as endometriosis.</strong> Central to the NeoFertility protocol, reproductive immunology evaluation includes NK cell panels (natural killer cell activity), antiphospholipid antibody testing, food antibody screening, and chronic endometritis workup. Treatment modalities include low-dose naltrexone (LDN), intralipid infusions, corticosteroids, and anticoagulation therapy.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_restorative-andrology', 'restorative-andrology', 'Restorative Andrology', 'VII', 2, '<p><strong>Male-partner evaluation and treatment within the RRM framework, focused on identifying and correcting the underlying causes of male factor infertility.</strong> Restorative andrology investigates varicocele, hormonal imbalance, oxidative stress, infection, sperm DNA fragmentation, and lifestyle contributors rather than bypassing male factor with intracytoplasmic sperm injection (ICSI). Treatment includes varicocelectomy, antioxidant therapy, hormonal correction, and lifestyle modification.<sup><a href="#ref-35">35</a></sup><sup><a href="#ref-53">53</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_migs', 'migs', 'Minimally Invasive Gynecologic Surgery (MIGS)', 'VII', 3, '<p><strong>Laparoscopic and hysteroscopic surgical techniques used in RRM for excision of endometriosis, adhesiolysis, isthmocele repair, myomectomy, and tubal surgery.</strong> MIGS emphasizes tissue preservation and fertility-sparing approaches, removing pathology while maintaining or restoring the structural and functional integrity of reproductive organs. Robotic-assisted and mini-laparotomy techniques are included under this umbrella.<sup><a href="#ref-10">10</a></sup><sup><a href="#ref-17">17</a></sup></p>', 'MIGS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cycle-timed-diagnostics', 'cycle-timed-diagnostics', 'Cycle-Timed Diagnostics', 'VII', 4, '<p><strong>The core RRM concept of ordering hormone panels, ultrasounds, and other tests at specific points in the menstrual cycle rather than on random calendar dates.</strong> By timing bloodwork to charting-identified events (e.g., post-peak day +7 for progesterone, early follicular phase for FSH and estradiol), clinicians detect luteal phase deficiency, anovulation, and hormonal patterns that random-draw testing misses. Cycle-timed diagnostics is what makes fertility charting clinically actionable, not merely observational.<sup><a href="#ref-3">3</a></sup><sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pelvic-floor-physical-therapy', 'pelvic-floor-physical-therapy', 'Pelvic Floor Physical Therapy', 'VII', 5, '<p><strong>Specialized rehabilitation addressing musculoskeletal contributors to chronic pelvic pain, dyspareunia, and voiding dysfunction.</strong> Part of the multidisciplinary RRM care team for patients with overlapping gynecologic and musculoskeletal pathology. Pelvic floor therapists assess and treat hypertonic pelvic floor muscles, myofascial trigger points, scar tissue restrictions, and neuromuscular dysfunction that coexist with conditions like endometriosis and adenomyosis.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fertilitycare-practice', 'fertilitycare-practice', 'FertilityCare Practice', 'VII', 6, '<p><strong>The professional discipline of teaching fertility awareness charting methods to patients.</strong> FertilityCare Practitioners (FCPs) are credentialed through the American Academy of FertilityCare Professionals (AAFCP) and serve as the charting education arm of the NaPro care model. FCPs teach the Creighton Model FertilityCare System and provide ongoing follow-up to ensure accurate charting. In RRM broadly, certified instructors for each method (FEMM Teachers, Marquette instructors, sympto-thermal educators) fill an equivalent role within their respective clinical systems.<sup><a href="#ref-7">7</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_functional-nutritional-medicine', 'functional-nutritional-medicine', 'Functional and Nutritional Medicine', 'VII', 7, '<p><strong>Assessment and optimization of nutritional status, metabolic markers, and lifestyle factors as part of reproductive health restoration.</strong> Includes evaluation of vitamin D, folate, B12, iron, zinc, omega-3 fatty acids, insulin resistance, inflammatory markers, and environmental toxin exposure. In RRM, nutritional and metabolic assessment is not adjunctive. It is part of the core diagnostic workup, addressing modifiable factors that directly affect ovulation, implantation, and pregnancy maintenance.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_napro-vs-rrm', 'napro-vs-rrm', 'NaProTECHNOLOGY vs. RRM', 'VIII', 0, '<p><strong>NaProTECHNOLOGY (NaPro) is the most established and studied approach within restorative reproductive medicine</strong>, developed by Dr. Thomas Hilgers at the Pope Paul VI Institute and based on the Creighton Model. RRM is a broader category describing approaches that share the restorative philosophy. NaPro practitioners may or may not identify their work under the RRM label. Other approaches that share this philosophy include: NeoFertility, Marquette Method-based medical management, FEMM-based care, and various symptothermal or sympto-hormonal approaches. All share the common framework of using biomarker data from cycle charting to optimize normal reproductive function.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_iui', 'iui', 'IUI (Intrauterine Insemination)', 'VIII', 1, '<p><strong>A procedure in which washed and concentrated sperm are deposited directly into the uterine cavity via a thin catheter at the time of ovulation, bypassing cervical mucus filtration.</strong> IUI is classified as a form of assisted reproductive technology (ART) but is less invasive than IVF and does not involve external fertilization; conception, if it occurs, happens in the fallopian tube. Indications include mild male factor infertility, cervical factor infertility, single-parent or same-sex couple use of donor sperm, and some unexplained infertility cases. Per-cycle clinical pregnancy rates vary widely by age, sperm parameters, and underlying cause. IUI bypasses cervical mucus but does not correct the underlying cause of reduced fertility; within the RRM framework it is an adjunct or alternative rather than a restorative therapy. NaProTECHNOLOGY and NeoFertility protocols do not employ IUI, instead timing natural intercourse to cycle-identified fertile windows and correcting the underlying causes of subfertility in one or both partners.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ivf', 'ivf', 'IVF (In Vitro Fertilization)', 'VIII', 2, '<p><strong>A form of assisted reproductive technology in which mature oocytes are retrieved from the ovaries via transvaginal aspiration after controlled ovarian hyperstimulation, fertilized externally in the laboratory (by conventional IVF or intracytoplasmic sperm injection (ICSI)), cultured to cleavage or blastocyst stage, and transferred into the uterus as one or more embryos.</strong> IVF bypasses the natural reproductive process rather than restoring it. Remaining embryos may be cryopreserved for future transfer, donated, or discarded. Per-cycle live-birth rates decline sharply with maternal age; known risks and tradeoffs include ovarian hyperstimulation syndrome (OHSS), multiple pregnancy (when more than one embryo is transferred), increased rates of preterm birth and low birthweight, and ongoing registry-level uncertainty about long-term outcomes in offspring. Within the RRM framework, IVF is classified as a bypass technology that circumvents underlying anatomical, hormonal, and immunologic problems rather than correcting them. See <a href="#ivf-vs-rrm">IVF vs. RRM: Key Conceptual Distinctions</a> for a side-by-side comparison.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ivf-vs-rrm', 'ivf-vs-rrm', 'IVF vs. RRM: Key Conceptual Distinctions', 'VIII', 3, '<div class="table-wrap">
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_patient-centered-care', 'patient-centered-care', 'Patient-Centered Care', 'VIII', 4, '<p><strong>A guiding RRM value emphasizing patient understanding, informed consent, and active participation in health decisions.</strong> Fertility charting education gives patients direct insight into their own hormonal and physiological patterns. When treating for infertility or miscarriage, RRM clinicians treat the couple (both male and female) as a single unit.<sup><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_couple-based-treatment', 'couple-based-treatment', 'Couple-Based Treatment', 'VIII', 5, '<p><strong>The RRM principle that when infertility or recurrent miscarriage is the concern, both partners receive evaluation and treatment as a unit.</strong> Male factor is the sole cause of infertility in approximately 20% of couples and a contributing factor in another 30 to 40%. Both partners are always assessed in RRM. This approach supports the relationship and reduces the emotional burden that often falls disproportionately on the female partner.<sup><a href="#ref-35">35</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_minimally-invasive-surgery', 'minimally-invasive-surgery', 'Minimally Invasive Surgery (MIS)', 'VIII', 6, '<p><strong>Surgical techniques (laparoscopic, hysteroscopic, robotic-assisted, or via mini-laparotomy) that minimize tissue trauma</strong> compared to open abdominal surgery, leading to faster recovery, less pain, fewer complications, and often superior fertility preservation. MIS is standard practice in RRM for all applicable procedures.<sup><a href="#ref-1">1</a></sup></p>', 'MIS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_adhesion-prevention', 'adhesion-prevention', 'Adhesion Prevention', 'VIII', 7, '<p><strong>The active strategy employed in RRM/NaPro Surgery to minimize post-operative adhesion formation</strong> through meticulous hemostasis, careful tissue handling, thorough peritoneal irrigation, and the strategic use of anti-adhesion barriers (Gore-Tex membrane). One published NaPro series documented a mean adhesion score reduction from 33.3 to 6.0 over a decade with systematic barrier use.<sup><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_antioxidant-therapy', 'antioxidant-therapy', 'Antioxidant Therapy', 'VIII', 8, '<p><strong>The therapeutic use of antioxidant compounds to reduce oxidative stress in both male and female reproductive contexts.</strong> In males, antioxidants (vitamin C, E, CoQ10, zinc, selenium, L-carnitine, N-acetylcysteine) reduce sperm DNA fragmentation and improve sperm parameters. In females, antioxidants support oocyte quality, reduce endometriosis-related oxidative damage, and may support embryo development.<sup><a href="#ref-22">22</a></sup><sup><a href="#ref-19">19</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_nutritional-lifestyle-medicine', 'nutritional-lifestyle-medicine', 'Nutritional and Lifestyle Medicine', 'VIII', 9, '<p><strong>RRM incorporates assessment and optimization of nutritional status</strong> (vitamin D, folate, B12, iron, zinc, omega-3s) and lifestyle factors (sleep, stress, physical activity, body weight, environmental toxin exposure) as foundational elements of reproductive health restoration. Nutritional deficiencies and poor lifestyle factors are identified as contributing underlying factors, not peripheral concerns.<sup><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
