                <tbody>
                  <tr><td>Hysteroscopic</td><td>Internal shaving/cautery of defect</td><td>Bleeding symptoms; RMT &gt;5mm; no future pregnancy desired</td><td>Faster recovery; may not fully resolve bleeding; does not rebuild wall<sup><a href="#ref-34">34</a></sup></td></tr>
                  <tr><td>Laparoscopic</td><td>Excision + multi-layer reconstruction</td><td>Fertility desire; RMT &lt;5mm; preferred overall</td><td>Rebuilds wall integrity; better symptom resolution; longer recovery<sup><a href="#ref-15">15</a></sup></td></tr>
                  <tr><td>Combined</td><td>Laparoscopic + hysteroscopic</td><td>Complex defects</td><td>Allows concurrent visualization of cavity and external repair</td></tr>
