            <p>Often co-exist; combined deficits are termed oligoasthenoteratospermia (OAT syndrome).</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
            <ul>
